import json
import pandas as pd

# Read the file with packageinfo results
with open('/tmp/tmphfwx1rq6.json', 'r') as f:
    packages = json.load(f)

# Filter for NPM packages with MIT license and release status
filtered_packages = []
for pkg in packages:
    # Check if it's NPM and MIT license
    if pkg['System'] == 'NPM' and 'MIT' in pkg['Licenses']:
        # Check if it's a release version
        try:
            version_info = json.loads(pkg['VersionInfo'])
            if version_info.get('IsRelease') == True:
                filtered_packages.append({
                    'System': pkg['System'],
                    'Name': pkg['Name'],
                    'Version': pkg['Version']
                })
        except:
            # Fallback: check if VersionInfo string contains IsRelease=true
            if '"IsRelease": true' in pkg['VersionInfo'] or '"IsRelease":true' in pkg['VersionInfo']:
                filtered_packages.append({
                    'System': pkg['System'],
                    'Name': pkg['Name'],
                    'Version': pkg['Version']
                })

print('__RESULT__:')
print(json.dumps(filtered_packages))

